Source code in <code>src/utils.py</code> <pre><code>def convert_numpy_to_list(data):
    new_data = []
    is_list = False
    try:
        if not isinstance(data, str):
            # ignore string which is also iterable
            iter(data)
            is_list = True
    except TypeError:
